-- Create "final_reports" table
CREATE TABLE "final_reports" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "correlation_key" character varying NOT NULL,
  "idempotency_key" character varying NOT NULL,
  "title" character varying NOT NULL,
  "executive_summary" character varying NOT NULL,
  "severity" character varying NOT NULL,
  "confidence" character varying NOT NULL,
  "subreport_summaries" jsonb NOT NULL,
  "recommended_actions" jsonb NOT NULL,
  "notification_text" character varying NOT NULL,
  "content" jsonb NOT NULL,
  "model" character varying NULL,
  "output_mode" character varying NULL,
  "created_by_workflow" character varying NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "final_reports_idempotency_key_key" to table: "final_reports"
CREATE UNIQUE INDEX "final_reports_idempotency_key_key" ON "final_reports" ("idempotency_key");
-- Create index "finalreport_correlation_key_created_at" to table: "final_reports"
CREATE INDEX "finalreport_correlation_key_created_at" ON "final_reports" ("correlation_key", "created_at");
-- Create index "finalreport_severity_created_at" to table: "final_reports"
CREATE INDEX "finalreport_severity_created_at" ON "final_reports" ("severity", "created_at");
-- Create "sub_reports" table
CREATE TABLE "sub_reports" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "idempotency_key" character varying NOT NULL,
  "scenario" character varying NOT NULL,
  "title" character varying NOT NULL,
  "summary" character varying NOT NULL,
  "severity" character varying NOT NULL,
  "confidence" character varying NOT NULL,
  "findings" jsonb NOT NULL,
  "recommended_actions" jsonb NOT NULL,
  "evidence_refs" jsonb NOT NULL,
  "content" jsonb NOT NULL,
  "model" character varying NULL,
  "output_mode" character varying NULL,
  "created_by_workflow" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "evidence_snapshot_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "sub_reports_evidence_snapshots_sub_reports" FOREIGN KEY ("evidence_snapshot_id") REFERENCES "evidence_snapshots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "subreport_evidence_snapshot_id_created_at" to table: "sub_reports"
CREATE INDEX "subreport_evidence_snapshot_id_created_at" ON "sub_reports" ("evidence_snapshot_id", "created_at");
-- Create index "subreport_evidence_snapshot_id_idempotency_key" to table: "sub_reports"
CREATE UNIQUE INDEX "subreport_evidence_snapshot_id_idempotency_key" ON "sub_reports" ("evidence_snapshot_id", "idempotency_key");
-- Create index "subreport_severity_created_at" to table: "sub_reports"
CREATE INDEX "subreport_severity_created_at" ON "sub_reports" ("severity", "created_at");
-- Create "final_report_sub_reports" table
CREATE TABLE "final_report_sub_reports" (
  "final_report_id" bigint NOT NULL,
  "sub_report_id" bigint NOT NULL,
  PRIMARY KEY ("final_report_id", "sub_report_id"),
  CONSTRAINT "final_report_sub_reports_final_report_id" FOREIGN KEY ("final_report_id") REFERENCES "final_reports" ("id") ON UPDATE NO ACTION ON DELETE CASCADE,
  CONSTRAINT "final_report_sub_reports_sub_report_id" FOREIGN KEY ("sub_report_id") REFERENCES "sub_reports" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
